const startConsumer = async () => {
    let connection;
    try {
        connection = await amqp.connect(RABBITMQ_URL);
        const channel = await connection.createChannel();

        await channel.assertQueue(QUEUE_NAME, {
            durable: true // Ensure queue survives RabbitMQ restarts
        });

        console.log(`[*] Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

        channel.consume(QUEUE_NAME, async (msg) => {
            if (msg !== null) {
                const success = await processMessage(msg);
                if (success) {
                    channel.ack(msg); // Acknowledge message if successfully processed
                } else {
                    // For example, if JSON parsing failed or a recoverable error occurred,
                    // you might nack it with requeue=true
                    // For unrecoverable errors, requeue=false or send to dead-letter queue
                    console.error(`[NACK] Message processing failed, nacking message:`, msg.content.toString());
                    channel.nack(msg, false, true); // requeue: true
                }
            }
        }, {
            noAck: false // Explicitly set to false, we will manually acknowledge messages
        });

        // Handle connection close
        connection.on('close', () => {
            console.error('[AMQP] Connection closed, attempting to reconnect...');
            setTimeout(startConsumer, 5000); // Reconnect after 5 seconds
        });
        connection.on('error', (err) => {
            console.error('[AMQP] Connection error:', err);
            if (err.message !== 'Connection closing') {
                connection.close();
            }
        });

    } catch (error) {
        console.error('[AMQP] Failed to connect to RabbitMQ or start consumer:', error.message);
        console.log('Retrying in 5 seconds...');
        setTimeout(startConsumer, 5000); // Retry connection after 5 seconds
    }
};

